module t(/*AUTOARG*/
   // Inputs
   clk
   );
   input clk;


localparam ASG0_DEPTH           = 4;
localparam ASG0_ADDR_WIDTH      = 2;

localparam ASG0_PTR_WIDTH       = (ASG0_DEPTH == 1) ? 1 : ASG0_ADDR_WIDTH + 1;
localparam ASG0_PTR_DEPTH       = 2 ** ASG0_PTR_WIDTH;
localparam ASG0_PTR_HALF_DEPTH  = 2 ** (ASG0_PTR_WIDTH - 1);

localparam logic [2*ASG0_DEPTH-1:0][ASG0_PTR_WIDTH-1:0] ASG0_GRAY_CODE = {3'h0, 3'h1, 3'h3, 3'h2, 3'h6, 3'h7, 3'h5, 3'h4};

localparam logic [ASG0_PTR_DEPTH-1:0][ASG0_ADDR_WIDTH-1:0]  ASG0_GRAY_CODE_INDEX    = asg0_gray_code_index_f(ASG0_GRAY_CODE);

    // -----------------------------
    // build gray code length 2 * ASG0_DEPTH
    // -----------------------------

    function automatic logic [ASG0_PTR_DEPTH-1:0][ASG0_ADDR_WIDTH-1:0] asg0_gray_code_index_f
        (
        logic [2*ASG0_DEPTH-1:0][ASG0_PTR_WIDTH-1:0]        x_code
        );

        logic [ASG0_PTR_DEPTH-1:0][ASG0_ADDR_WIDTH-1:0]     y_index;
        logic [ASG0_PTR_DEPTH-1:0]                          z_fill;

        // build lookup table

        y_index     = '0;

        for (int k0=0; k0<2*ASG0_DEPTH; k0++)
            {z_fill[k0], y_index[x_code[k0]]}   = k0[ASG0_PTR_WIDTH-1:0] % ASG0_DEPTH;

        // return

        return y_index;

    endfunction

    initial begin

       logic [ASG0_PTR_DEPTH-1:0][ASG0_ADDR_WIDTH-1:0] index = asg0_gray_code_index_f(ASG0_GRAY_CODE);
       if (index !== ASG0_GRAY_CODE_INDEX) $stop;
        
       $write("*-* All Finished *-*\n");
       $finish;
    end

endmodule

